// =============================================================================
// GENERATED SAVED-CONFIG DATE/TIME HELPERS - do not edit by hand
// Generated by scripts/build.py from common/config/card_contract.json.
// =============================================================================
import type { CardConfig } from "../contracts/types";

export type SavedConfigDateTimeFieldHook = (config: CardConfig) => void;
export type SavedConfigDateTimeOptionHook = (options: string, config: CardConfig) => string;

export function normalizeSavedConfigDateTime(
  config: CardConfig,
  normalizeFields: SavedConfigDateTimeFieldHook,
  normalizeOptions: SavedConfigDateTimeOptionHook,
): boolean {
  if (config.type === "calendar") {
    normalizeFields(config);
    config.label = "";
    config.icon = "Auto";
    config.icon_on = "Auto";
    config.sensor = "";
    config.unit = "";
    config.type = "calendar";
    if (config.precision !== "" && config.precision !== "datetime") config.precision = "";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  if (config.type === "clock") {
    config.entity = "";
    config.label = "";
    config.icon = "Auto";
    config.icon_on = "Auto";
    config.sensor = "";
    config.unit = "";
    config.type = "clock";
    config.precision = "";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  if (config.type === "timezone") {
    normalizeFields(config);
    config.label = "";
    config.icon = "Auto";
    config.icon_on = "Auto";
    config.sensor = "";
    config.unit = "";
    config.type = "timezone";
    config.precision = "";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  return false;
}
